import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd } from '../../../utils/formatters';
import { MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { PayslipRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-luong';
const PAGE_ID = 'baocao-luong';

const BaoCaoLuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<PayslipRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getPayslips({ month, year })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select label="Tháng" value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select label="Năm" value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
            </div>
          </>
        )}
      />
    ),
    [month, year, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo lương"
      titleIconClass="fas fa-money-check-alt"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/hr/payslips/export-excel"
      exportParams={{ month, year }}
      exportFilename={`BaoCaoLuong-T${month}-${year}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Mã NV</th>
            <th>Họ tên</th>
            <th>PB</th>
            <th className={reportStyles.colRight}>Thu nhập</th>
            <th className={reportStyles.colRight}>Khấu trừ</th>
            <th className={reportStyles.colRight}>Thực lĩnh</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={r.id ?? i}>
              <td>{r.employeeCode}</td>
              <td>{r.employeeName}</td>
              <td>{r.departmentName ?? '—'}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.grossIncome)}</td>
              <td className={reportStyles.colRight}>
                {formatVnd((r.socialInsuranceEmployee ?? 0) + (r.personalIncomeTax ?? 0))}
              </td>
              <td className={reportStyles.colRight}>{formatVnd(r.netSalary)}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoLuongPage;
